/**
 * Logos do cabeçalho da receita (SUS, UFTM, HU-Brasil/EBSERH), embutidos como
 * data-URI (o HTML de impressão é autocontido). Extraídos dos SVGs oficiais
 * enviados pela equipe (JPEG embutido). NÃO editar os data-URI à mão.
 */
export interface ReceitaLogo {
  sigla: string;
  nome: string;
  /** data-URI da imagem. Vazio → mostra a sigla. */
  src: string;
}

export const RECEITA_LOGOS: ReceitaLogo[] = [
  { sigla: "SUS", nome: "SUS", src: "data:image/jpeg;base64," },
  { sigla: "UFTM", nome: "UFTM", src: "data:image/png;base64," },
  { sigla: "HU-Brasil", nome: "HU-Brasil / EBSERH", src: "data:image/png;base64," },
];
